export const RUNELITE_AGILITY_OBSTACLE_IDS = RUNELITE_AGILITY_OBSTACLE_ID_ENTRIES.map((entry) => entry.id);

const RUNELITE_AGILITY_OBSTACLE_ID_SET: ReadonlySet<number> = new Set(RUNELITE_AGILITY_OBSTACLE_IDS);
const RUNELITE_AGILITY_OBSTACLE_KEY_BY_ID: ReadonlyMap<number, string> = new Map(
  RUNELITE_AGILITY_OBSTACLE_ID_ENTRIES.map((entry) => [entry.id, entry.key] as const),
);

export function isRuneliteAgilityObstacleId(id: number): boolean {
  return RUNELITE_AGILITY_OBSTACLE_ID_SET.has(id);
}

export function getRuneliteAgilityObstacleKey(id: number): string | null {
  return RUNELITE_AGILITY_OBSTACLE_KEY_BY_ID.get(id) ?? null;
}
